@Service
public class AccountService {

    @Transactional(isolation = Isolation.SERIALIZABLE)
    public void transferFunds(String fromAccount, String toAccount,
            BigDecimal amount) {

        // Step 1: Debit source account
        Account source = accountRepository.findById(fromAccount)
            .orElseThrow(() -> new AccountNotFoundException());
        source.setBalance(source.getBalance().subtract(amount));
        accountRepository.save(source);  // Immediately persisted

        // Step 2: Credit destination account
        Account dest = accountRepository.findById(toAccount)
            .orElseThrow(() -> new AccountNotFoundException());
        dest.setBalance(dest.getBalance().add(amount));
        accountRepository.save(dest);  // Immediately persisted

        // Step 3: Log transaction
        TransactionLog log = new TransactionLog(
            fromAccount, toAccount, amount, TransactionStatus.COMPLETED);
        transactionLogRepository.save(log);

        // All 3 operations commit together or all rollback
    }
}
```

**3. Write-Ahead Logging (WAL)**:
```java
@Service
public class WALTransactionLogger {

    // Simulates database Write-Ahead Log
    @Autowired
    private TransactionLogRepository logRepository;

    @Transactional
    public void executeWithWAL(Transaction transaction) {
        // Step 1: Write to WAL first (durable before execution)
        TransactionLog walEntry = new TransactionLog();
        walEntry.setStatus(TransactionStatus.PENDING);
        walEntry.setData(transaction);
        walEntry.setTimestamp(LocalDateTime.now());
        logRepository.save(walEntry);

        // Step 2: Execute transaction
        try {
            executeTransaction(transaction);

            // Step 3: Mark WAL as committed
            walEntry.setStatus(TransactionStatus.COMMITTED);
            logRepository.save(walEntry);

        } catch (Exception e) {
            // Step 3: Mark WAL as failed
            walEntry.setStatus(TransactionStatus.FAILED);
            logRepository.save(walEntry);
            throw e;
        }
    }
}
```

