**6. Saga Pattern with Compensating Transactions**:
```java
@Service
public class PaymentSagaOrchestrator {

    @Transactional
    public void executePaymentSaga(PaymentRequest request) {
        PaymentSagaState sagaState = new PaymentSagaState(request);
        sagaStateRepository.save(sagaState);

        try {
            // Step 1
            inventoryService.reserve(request.getItems());
            sagaState.markStepCompleted("inventory");
            sagaStateRepository.save(sagaState);

            // Step 2
            paymentService.charge(request.getPayment());
            sagaState.markStepCompleted("payment");
            sagaStateRepository.save(sagaState);

            // Step 3
            shippingService.createShipment(request);
            sagaState.markStepCompleted("shipping");
            sagaStateRepository.save(sagaState);

            sagaState.markCompleted();
            sagaStateRepository.save(sagaState);

        } catch (Exception e) {
            // Compensate: reverse completed steps
            if (sagaState.isStepCompleted("shipping")) {
                shippingService.cancelShipment(sagaState.getShipmentId());
            }
            if (sagaState.isStepCompleted("payment")) {
                paymentService.refund(sagaState.getPaymentId());
            }
            if (sagaState.isStepCompleted("inventory")) {
                inventoryService.release(request.getItems());
            }

            sagaState.markFailed();
            sagaStateRepository.save(sagaState);
            throw e;
        }
    }
}
```

